def first_fit_decreasing_bin_packing(item_sizes, bin_capacity):
    # Sort the item sizes in non-increasing order
    sorted_item_sizes = sorted(item_sizes, reverse=True)

    # Initialize an array of bins with capacities
    bins = [bin_capacity]

    # Iterate through the sorted item sizes and pack them into bins
    for size in sorted_item_sizes:
        placed = False
        for i in range(len(bins)):
            if bins[i] >= size:
                bins[i] -= size
                placed = True
                break
        if not placed:
            bins.append(bin_capacity - size)

    # The number of used bins is the answer
    return len(bins)


t = int(input())
for _ in range(t):
    N, M = map(int, input().split())
    arr = list(map(int, input().split()))
    result = first_fit_decreasing_bin_packing(arr, M)
    print(result)

